function int calc_sums(int s[], int n);
  int sum = 0;
  for (int ii = 0; ii < n; ii++) sum = sum + s[ii];
  return sum;
endfunction
parameter int SIZES[4] = '{1,2,3,4};
parameter int result = calc_sums(SIZES, 4);

typedef int calc_sums_t[4];
function calc_sums_t calc_sums(int s[], int n);
endfunction
parameter int SIZES[4] = '{1,2,3,4};
parameter calc_sums_t SUMS = calc_sums(SIZES, 4);
